INDEX_HTML = '<!DOCTYPE html>\n<html lang="az">\n<head>\n<meta charset="UTF-8" />\n<meta name="viewport" content="width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no" />\n<title>Del Monte Ferma</title>\n<link rel="icon" href="/logo.png" />\n<style>\n  :root{\n    --green:#12b886; --green-d:#0ca678;\n    --orange:#f9a825; --orange-d:#f57f17;\n    --red:#e53935; --red-d:#c62828;\n    --brown:#8d5524; --wood:#a9763f;\n    --ink:#2b2b2b; --muted:#8a8a8a;\n    --card:#ffffff; --line:#eee;\n  }\n  *{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}\n  body{font-family:\'Segoe UI\',system-ui,Arial,sans-serif;color:var(--ink);background:#f4efe6}\n  #app{max-width:480px;margin:0 auto;min-height:100vh;position:relative;background:#f4efe6;overflow:hidden}\n  img{display:block}\n  .hidden{display:none!important}\n  button{font-family:inherit;cursor:pointer;border:none}\n\n  /* AWNING HEADER */\n  .awning{position:relative;height:70px;background:\n    repeating-linear-gradient(90deg,var(--orange) 0 34px,#fff 34px 68px);}\n  .awning::after{content:"";position:absolute;bottom:-18px;left:0;right:0;height:22px;\n    background:repeating-linear-gradient(90deg,var(--orange) 0 34px,#fff 34px 68px);\n    -webkit-mask:radial-gradient(circle 17px at 17px 0,transparent 16px,#000 17px) repeat-x;\n    -webkit-mask-size:34px 22px;mask:radial-gradient(circle 17px at 17px 0,transparent 16px,#000 17px) repeat-x;mask-size:34px 22px;}\n  .starbar{position:absolute;top:6px;left:50%;transform:translateX(-50%);background:var(--red);\n    color:var(--orange);border-radius:10px;padding:6px 16px;font-size:13px;letter-spacing:2px;\n    box-shadow:0 4px 0 var(--red-d);z-index:3;white-space:nowrap}\n\n  /* AUTH */\n  .auth-wrap{min-height:100vh;background:linear-gradient(180deg,#8fd3f4,#a7e9af);display:flex;flex-direction:column;align-items:center;padding:26px 20px 40px}\n  .auth-logo{width:150px;height:auto;filter:drop-shadow(0 6px 10px rgba(0,0,0,.25));margin-top:8px}\n  .auth-card{background:#fff;border-radius:22px;padding:24px 20px;width:100%;max-width:400px;margin-top:22px;box-shadow:0 14px 34px rgba(0,0,0,.15)}\n  .auth-card h2{text-align:center;color:var(--green-d);margin-bottom:4px;font-size:22px}\n  .auth-card p.sub{text-align:center;color:var(--muted);font-size:13px;margin-bottom:18px}\n  label{display:block;font-size:13px;font-weight:600;margin:12px 2px 6px}\n  .field{display:flex;gap:8px}\n  .prefix{background:#f0f0f0;border-radius:12px;display:flex;align-items:center;padding:0 12px;font-weight:700;color:#555}\n  select,input{width:100%;padding:14px;border:1.5px solid #e5e5e5;border-radius:12px;font-size:15px;outline:none;background:#fafafa}\n  select:focus,input:focus{border-color:var(--green)}\n  select.op{width:auto;min-width:90px;font-weight:700}\n  .btn{width:100%;padding:15px;border-radius:14px;font-size:16px;font-weight:700;color:#fff;background:var(--green);box-shadow:0 5px 0 var(--green-d);margin-top:20px;transition:.1s}\n  .btn:active{transform:translateY(3px);box-shadow:0 2px 0 var(--green-d)}\n  .btn.orange{background:var(--orange);box-shadow:0 5px 0 var(--orange-d)}\n  .switch{text-align:center;margin-top:16px;font-size:14px;color:#555}\n  .switch b{color:var(--green-d);cursor:pointer}\n  .hint{font-size:11.5px;color:var(--muted);margin-top:5px}\n\n  /* MAIN */\n  .topbar{display:flex;align-items:center;gap:10px;padding:12px 14px;background:linear-gradient(90deg,var(--wood),#c8925a);color:#fff;\n    border-bottom:4px solid #7a5327}\n  .avatar{width:46px;height:46px;border-radius:12px;background:#fff2d9;display:flex;align-items:center;justify-content:center;font-size:24px;border:2px solid #fff}\n  .tb-info{flex:1}\n  .tb-info .lvl{font-size:12px;opacity:.9}\n  .tb-info .coins{font-size:20px;font-weight:800;display:flex;align-items:center;gap:6px}\n  .tb-logo{width:52px;height:auto}\n\n  .screen{padding:16px 14px 96px;min-height:calc(100vh - 66px)}\n  .farm{background:url(\'/farm-bg.jpg\') center/cover;border-radius:0;min-height:calc(100vh - 66px);padding:16px 14px 110px;position:relative}\n  .quick{display:flex;justify-content:space-between;margin-bottom:14px}\n  .quick .q{display:flex;flex-direction:column;align-items:center;gap:4px;font-size:12px;font-weight:600;color:#3a3a3a;background:rgba(255,255,255,.75);padding:8px;border-radius:14px;width:72px}\n  .quick .q .ic{font-size:26px}\n\n  .plots{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-top:6px}\n  .plot{background:rgba(255,255,255,.9);border-radius:16px;padding:10px 8px;text-align:center;box-shadow:0 4px 10px rgba(0,0,0,.12);position:relative}\n  .plot .emoji{font-size:40px;line-height:1}\n  .plot .nm{font-size:12px;font-weight:700;margin-top:2px}\n  .plot .timer{font-size:11px;color:var(--red-d);font-weight:700;margin:3px 0}\n  .plot .acts{display:flex;gap:5px;margin-top:5px}\n  .plot .acts button{flex:1;font-size:11px;font-weight:700;color:#fff;border-radius:8px;padding:6px 0}\n  .a-water{background:#3aa0ff}\n  .a-harvest{background:var(--orange)}\n  .empty-plot{background:rgba(255,255,255,.55);border-radius:16px;min-height:110px;display:flex;align-items:center;justify-content:center;color:#666;font-size:12px;border:2px dashed rgba(0,0,0,.15)}\n\n  .sectiontitle{font-size:22px;font-weight:800;color:var(--orange-d);margin:4px 2px 14px}\n  .card{background:var(--card);border-radius:16px;padding:14px;margin-bottom:12px;box-shadow:0 4px 12px rgba(0,0,0,.06)}\n  .shop-item{display:flex;gap:12px;align-items:center}\n  .shop-item .emoji{font-size:52px;width:64px;text-align:center}\n  .shop-item .info{flex:1;font-size:13px}\n  .shop-item .info .t{font-size:16px;font-weight:800;margin-bottom:4px}\n  .shop-item .row{color:#555;margin:2px 0}\n  .shop-item .row b{color:var(--green-d)}\n  .buybtn{background:var(--orange);color:#fff;font-weight:800;padding:10px 18px;border-radius:12px;box-shadow:0 4px 0 var(--orange-d);align-self:center}\n  .buybtn:active{transform:translateY(2px);box-shadow:0 2px 0 var(--orange-d)}\n\n  .infobox{background:#fff7e6;border:1px solid #ffe0a3;border-radius:12px;padding:12px;font-size:13px;line-height:1.6;margin-bottom:14px}\n  .infobox b{color:var(--red-d)}\n  .tag{display:inline-block;background:#e7f9f2;color:var(--green-d);font-weight:800;padding:3px 10px;border-radius:8px}\n  .tglink{display:flex;align-items:center;gap:10px;background:#e8f4ff;border-radius:12px;padding:12px;margin-bottom:10px;text-decoration:none;color:#0b6bcb;font-weight:700}\n  .tglink .ic{font-size:24px}\n\n  .stat-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px}\n  .stat{background:linear-gradient(135deg,#12b886,#0ca678);color:#fff;border-radius:14px;padding:14px;text-align:center}\n  .stat .v{font-size:22px;font-weight:800}\n  .stat .l{font-size:12px;opacity:.9}\n  .reflink{display:flex;gap:8px;margin:12px 0}\n  .reflink input{background:#f5f5f5}\n  .copybtn{background:var(--green);color:#fff;font-weight:700;padding:0 18px;border-radius:12px;white-space:nowrap;box-shadow:0 4px 0 var(--green-d)}\n\n  .tx{display:flex;justify-content:space-between;padding:12px 4px;border-bottom:1px solid var(--line);font-size:14px}\n  .tx .d{font-size:11px;color:var(--muted)}\n  .tx .amt{font-weight:800}\n  .pos{color:var(--green-d)} .neg{color:var(--red)}\n  .badge{font-size:11px;padding:2px 8px;border-radius:8px}\n  .b-pending{background:#fff3cd;color:#8a6d00}\n  .b-completed{background:#d4edda;color:#1c7c34}\n  .b-rejected{background:#f8d7da;color:#a52834}\n\n  .backbtn{background:none;color:var(--orange-d);font-weight:700;font-size:14px;margin-bottom:8px}\n\n  /* BOTTOM NAV */\n  .nav{position:fixed;bottom:0;left:50%;transform:translateX(-50%);width:100%;max-width:480px;display:flex;background:linear-gradient(180deg,#c8925a,var(--wood));border-top:4px solid #7a5327;z-index:40}\n  .nav button{flex:1;color:#fff;background:none;padding:9px 2px 10px;font-size:11px;font-weight:600;display:flex;flex-direction:column;align-items:center;gap:3px;opacity:.85}\n  .nav button.active{opacity:1;color:#ffe9b0}\n  .nav .ic{font-size:20px}\n\n  /* TOAST + MODAL */\n  #toast{position:fixed;top:24px;left:50%;transform:translateX(-50%);background:#333;color:#fff;padding:12px 22px;border-radius:30px;font-size:14px;z-index:200;opacity:0;transition:.25s;pointer-events:none;max-width:90%;text-align:center}\n  #toast.show{opacity:1;top:34px}\n  .modal{position:fixed;inset:0;background:rgba(0,0,0,.5);display:flex;align-items:center;justify-content:center;z-index:150;padding:24px}\n  .modal .box{background:#fff;border-radius:20px;padding:22px;width:100%;max-width:360px}\n  .modal h3{margin-bottom:14px;color:var(--green-d)}\n  .modal .x{float:right;font-size:22px;color:#999;cursor:pointer}\n</style>\n</head>\n<body>\n<div id="app">\n\n  <!-- ===== AUTH ===== -->\n  <div id="authScreen" class="auth-wrap">\n    <img class="auth-logo" src="/logo.png" alt="Del Monte" />\n    <div class="auth-card">\n      <!-- LOGIN -->\n      <div id="loginForm">\n        <h2>Xoş gəldiniz</h2>\n        <p class="sub">Del Monte Ferma hesabınıza daxil olun</p>\n        <label>Telefon nömrəsi</label>\n        <div class="field">\n          <span class="prefix">+994</span>\n          <select id="lgOp" class="op">\n            <option>50</option><option>51</option><option>55</option><option>70</option>\n            <option>77</option><option>99</option><option>10</option><option>12</option>\n            <option>40</option><option>44</option><option>60</option>\n          </select>\n          <input id="lgNum" inputmode="numeric" maxlength="7" placeholder="5555555" />\n        </div>\n        <label>Şifrə</label>\n        <input id="lgPass" type="password" placeholder="Şifrənizi daxil edin" />\n        <button class="btn" onclick="login()">Daxil ol</button>\n        <div class="switch">Hesabınız yoxdur? <b onclick="showAuth(\'reg\')">Qeydiyyat</b></div>\n      </div>\n      <!-- REGISTER -->\n      <div id="regForm" class="hidden">\n        <h2>Qeydiyyat</h2>\n        <p class="sub">🎁 Qeydiyyatdan keçən hər kəsə 1 AZN bonus!</p>\n        <label>Telefon nömrəsi</label>\n        <div class="field">\n          <span class="prefix">+994</span>\n          <select id="rgOp" class="op">\n            <option>50</option><option>51</option><option>55</option><option>70</option>\n            <option>77</option><option>99</option><option>10</option><option>12</option>\n            <option>40</option><option>44</option><option>60</option>\n          </select>\n          <input id="rgNum" inputmode="numeric" maxlength="7" placeholder="5555555" />\n        </div>\n        <div class="hint">Nümunə: +994 55 5555555 (operator + 7 rəqəm)</div>\n        <label>Şifrə</label>\n        <input id="rgPass" type="password" placeholder="6-20 simvol" />\n        <label>Referal kodu (istəyə görə)</label>\n        <input id="rgRef" placeholder="Dəvət kodu" />\n        <button class="btn orange" onclick="register()">Qeydiyyatdan keç</button>\n        <div class="switch">Hesabınız var? <b onclick="showAuth(\'login\')">Daxil ol</b></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ===== MAIN ===== -->\n  <div id="mainScreen" class="hidden">\n    <div class="topbar">\n      <div class="avatar">🧑\u200d🌾</div>\n      <div class="tb-info">\n        <div class="lvl">Lv. <span id="uLevel">1</span></div>\n        <div class="coins">🪙 <span id="uBalance">0.00</span></div>\n      </div>\n      <img class="tb-logo" src="/logo.png" alt="Del Monte" />\n    </div>\n\n    <!-- HOME / FARM -->\n    <div id="tab-home">\n      <div class="farm">\n        <div class="quick">\n          <div class="q" onclick="go(\'treasure\')"><span class="ic">🎁</span>Kodu geri alın</div>\n          <div class="q" onclick="go(\'deposit\')"><span class="ic">💰</span>Depozit</div>\n          <div class="q" onclick="go(\'invite\')"><span class="ic">👥</span>Dəvət et</div>\n          <div class="q" onclick="loadProfile(true)"><span class="ic">🔄</span>Yenilə</div>\n        </div>\n        <div id="myPlots" class="plots"></div>\n      </div>\n    </div>\n\n    <!-- SEED MALL -->\n    <div id="tab-shop" class="screen hidden">\n      <div class="starbar">★ ★ ★ ★ ★ ★ ★ ★ ★ ★</div>\n      <div class="sectiontitle" style="margin-top:36px">Seed Mall</div>\n      <div id="shopList"></div>\n    </div>\n\n    <!-- DEPOSIT -->\n    <div id="tab-deposit" class="screen hidden">\n      <div class="sectiontitle">Depozit</div>\n      <div class="infobox">\n        ⏰ Depozit saatları: <b>10:00 - 20:00</b><br>\n        💵 Minimum depozit: <b>10 AZN</b><br>\n        📲 Depozit üçün: <span class="tag">@Delmontedepozit</span>\n      </div>\n      <a class="tglink" href="https://t.me/Delmontedepozit" target="_blank"><span class="ic">📨</span> Depozit üçün Telegram-a yaz (@Delmontedepozit)</a>\n      <div class="card">\n        <label>Depozit məbləği (AZN)</label>\n        <input id="depAmount" inputmode="decimal" placeholder="Minimum 10 AZN" />\n        <button class="btn" onclick="submitDeposit()">Depozit sorğusu göndər</button>\n      </div>\n    </div>\n\n    <!-- WITHDRAW -->\n    <div id="tab-withdraw" class="screen hidden">\n      <div class="sectiontitle">Çıxarış</div>\n      <div class="infobox">\n        ⏰ Çıxarış saatları: <b>10:00 - 20:00</b><br>\n        💵 Minimum: <b>6 AZN</b> &nbsp; Maksimum: <b>2000 AZN</b><br>\n        📉 Komissiya: <b>10%</b>\n      </div>\n      <div class="card">\n        <label>Bank adı</label>\n        <input id="wBank" placeholder="Zəhmət olmasa bank adını daxil edin" />\n        <label>Ad Soyad</label>\n        <input id="wHolder" placeholder="Zəhmət olmasa adınızı yazın" />\n        <label>Bank kartı nömrəsi</label>\n        <input id="wCard" inputmode="numeric" placeholder="Kart nömrəsini daxil edin" />\n        <label>Çıxarış məbləği (AZN)</label>\n        <input id="wAmount" inputmode="decimal" placeholder="Minimum 6 AZN" />\n        <button class="btn" onclick="submitWithdraw()">Çıxarış sorğusu</button>\n      </div>\n    </div>\n\n    <!-- INVITE / REFERRAL -->\n    <div id="tab-invite" class="screen hidden">\n      <div class="sectiontitle">Dəvət et</div>\n      <div class="infobox">🤝 Dostunu dəvət et! Dəvət etdiyin şəxs depozit etdikdə sənə <b>10% cashback</b> gəlir.</div>\n      <div class="stat-grid">\n        <div class="stat"><div class="v" id="refCount">0</div><div class="l">Dəvət olunan</div></div>\n        <div class="stat"><div class="v" id="refCash">0.00</div><div class="l">Qazanılan cashback</div></div>\n      </div>\n      <div class="card">\n        <label>Dəvət kodun</label>\n        <div class="reflink">\n          <input id="myRefCode" readonly />\n          <button class="copybtn" onclick="copyVal(\'myRefCode\')">Kopyala</button>\n        </div>\n        <label>Dəvət linkin</label>\n        <div class="reflink">\n          <input id="myRefLink" readonly />\n          <button class="copybtn" onclick="copyVal(\'myRefLink\')">Kopyala</button>\n        </div>\n      </div>\n    </div>\n\n    <!-- TREASURE CODE -->\n    <div id="tab-treasure" class="screen hidden">\n      <div class="sectiontitle">🎁 Xəzinə kodu</div>\n      <div class="infobox">Xəzinə kodunu daxil edərək hesabına bonus qazan!</div>\n      <div class="card">\n        <label>Kodu daxil et</label>\n        <input id="treCode" placeholder="Xəzinə kodu" />\n        <button class="btn orange" onclick="redeemCode()">Kodu geri al</button>\n      </div>\n    </div>\n\n    <!-- ME / PROFILE -->\n    <div id="tab-me" class="screen hidden">\n      <div class="sectiontitle">Mənim</div>\n      <div class="stat-grid">\n        <div class="stat"><div class="v" id="mBalance">0.00</div><div class="l">Balans (AZN)</div></div>\n        <div class="stat"><div class="v" id="mIncome">0.00</div><div class="l">Ümumi gəlir</div></div>\n        <div class="stat"><div class="v" id="mDeposit">0.00</div><div class="l">Ümumi depozit</div></div>\n        <div class="stat"><div class="v" id="mWithdraw">0.00</div><div class="l">Ümumi çıxarış</div></div>\n      </div>\n      <div class="card" style="display:flex;gap:10px">\n        <button class="btn" style="margin-top:0" onclick="go(\'deposit\')">💰 Depozit</button>\n        <button class="btn orange" style="margin-top:0" onclick="go(\'withdraw\')">🏧 Çıxarış</button>\n      </div>\n      <div class="sectiontitle" style="font-size:18px">Müştəri xidməti</div>\n      <a class="tglink" href="https://t.me/delmonte01" target="_blank"><span class="ic">🎧</span> Müştəri xidməti: @delmonte01</a>\n      <a class="tglink" href="https://t.me/+SYVQ4JwgJ3M3ZGMx" target="_blank"><span class="ic">📢</span> Del Monte kanal</a>\n      <a class="tglink" href="https://t.me/+IvvXXzzOJIo2MDAx" target="_blank"><span class="ic">💬</span> Söhbət qrupu</a>\n      <div class="sectiontitle" style="font-size:18px">Əməliyyat tarixçəsi</div>\n      <div class="card" id="txList"><p style="color:#999;text-align:center">Yüklənir...</p></div>\n      <button class="btn" style="background:#c62828;box-shadow:0 5px 0 #8e1b1b" onclick="logout()">Çıxış et</button>\n    </div>\n\n    <!-- BOTTOM NAV -->\n    <div class="nav">\n      <button data-tab="home" class="active" onclick="go(\'home\')"><span class="ic">🏡</span>ön səhifə</button>\n      <button data-tab="shop" onclick="go(\'shop\')"><span class="ic">🌱</span>Seed Mall</button>\n      <button data-tab="home2" onclick="go(\'home\')"><span class="ic">🌾</span>ferma</button>\n      <button data-tab="withdraw" onclick="go(\'withdraw\')"><span class="ic">💵</span>satmaq</button>\n      <button data-tab="me" onclick="go(\'me\')"><span class="ic">👤</span>mənim</button>\n    </div>\n  </div>\n</div>\n\n<div id="toast"></div>\n\n<script>\nconst API = \'\';\nconst TREES = {\n  1:{name:\'Nar ağacı\',emoji:\'🍎\',price:10,daily:0.8,days:30},\n  2:{name:\'Armud ağacı\',emoji:\'🍐\',price:25,daily:1.8,days:30},\n  3:{name:\'Mpopla ağacı\',emoji:\'🫐\',price:100,daily:5.5,days:30},\n  4:{name:\'Banan ağacı\',emoji:\'🍌\',price:250,daily:12.5,days:30},\n  5:{name:\'Ananas ağacı\',emoji:\'🍍\',price:540,daily:28,days:30},\n  6:{name:\'Manqo ağacı\',emoji:\'🥭\',price:1000,daily:50,days:30},\n};\nlet token = localStorage.getItem(\'token\');\nlet profile = null;\n\nfunction toast(msg){const t=document.getElementById(\'toast\');t.textContent=msg;t.classList.add(\'show\');setTimeout(()=>t.classList.remove(\'show\'),2600);}\nfunction showAuth(w){document.getElementById(\'loginForm\').classList.toggle(\'hidden\',w!==\'login\');document.getElementById(\'regForm\').classList.toggle(\'hidden\',w!==\'reg\');}\n\nasync function api(path,method=\'GET\',body){\n  const h={\'Content-Type\':\'application/json\'};\n  if(token)h.Authorization=\'Bearer \'+token;\n  const r=await fetch(API+path,{method,headers:h,body:body?JSON.stringify(body):undefined});\n  const d=await r.json();\n  if(!r.ok)throw new Error(d.error||\'Xəta baş verdi\');\n  return d;\n}\n\n/* AUTH */\nasync function register(){\n  const op=document.getElementById(\'rgOp\').value;\n  const num=document.getElementById(\'rgNum\').value.trim();\n  const pass=document.getElementById(\'rgPass\').value;\n  const ref=document.getElementById(\'rgRef\').value.trim();\n  if(!/^\\d{7}$/.test(num))return toast(\'Nömrə 7 rəqəm olmalıdır\');\n  if(pass.length<6||pass.length>20)return toast(\'Şifrə 6-20 simvol olmalıdır\');\n  const phone=\'994\'+op+num;\n  try{\n    const d=await api(\'/api/auth/register\',\'POST\',{phone,password:pass,refCode:ref});\n    token=d.token;localStorage.setItem(\'token\',token);\n    toast(d.message||\'Qeydiyyat uğurlu!\');enterApp();\n  }catch(e){toast(e.message);}\n}\nasync function login(){\n  const op=document.getElementById(\'lgOp\').value;\n  const num=document.getElementById(\'lgNum\').value.trim();\n  const pass=document.getElementById(\'lgPass\').value;\n  if(!/^\\d{7}$/.test(num))return toast(\'Nömrə 7 rəqəm olmalıdır\');\n  const phone=\'994\'+op+num;\n  try{\n    const d=await api(\'/api/auth/login\',\'POST\',{phone,password:pass});\n    token=d.token;localStorage.setItem(\'token\',token);enterApp();\n  }catch(e){toast(e.message);}\n}\nfunction logout(){localStorage.removeItem(\'token\');token=null;location.reload();}\n\nfunction enterApp(){\n  document.getElementById(\'authScreen\').classList.add(\'hidden\');\n  document.getElementById(\'mainScreen\').classList.remove(\'hidden\');\n  loadProfile();renderShop();go(\'home\');\n}\n\n/* NAV */\nfunction go(tab){\n  [\'home\',\'shop\',\'deposit\',\'withdraw\',\'invite\',\'treasure\',\'me\'].forEach(t=>{\n    const el=document.getElementById(\'tab-\'+t);if(el)el.classList.toggle(\'hidden\',t!==tab);\n  });\n  document.querySelectorAll(\'.nav button\').forEach(b=>b.classList.remove(\'active\'));\n  const map={home:\'home\',shop:\'shop\',withdraw:\'withdraw\',me:\'me\'};\n  const active=map[tab];\n  if(active){const b=document.querySelector(\'.nav button[data-tab="\'+active+\'"]\');if(b)b.classList.add(\'active\');}\n  if(tab===\'invite\')loadReferral();\n  if(tab===\'me\'){loadProfile();loadTx();}\n  if(tab===\'home\')loadProfile();\n  window.scrollTo(0,0);\n}\n\n/* PROFILE */\nasync function loadProfile(notify){\n  try{\n    const d=await api(\'/api/user/profile\');\n    profile=d;\n    document.getElementById(\'uBalance\').textContent=(+d.user.balance).toFixed(2);\n    document.getElementById(\'uLevel\').textContent=d.user.level;\n    document.getElementById(\'mBalance\').textContent=(+d.user.balance).toFixed(2);\n    document.getElementById(\'mIncome\').textContent=(+d.user.total_income).toFixed(2);\n    document.getElementById(\'mDeposit\').textContent=(+d.user.total_deposit).toFixed(2);\n    document.getElementById(\'mWithdraw\').textContent=(+d.user.total_withdraw).toFixed(2);\n    renderPlots(d.trees);\n    if(notify)toast(\'Yeniləndi\');\n  }catch(e){if(e.message.includes(\'token\')||e.message.includes(\'Token\'))logout();}\n}\n\nfunction daysLeft(t){\n  const end=new Date(t.planted_at).getTime()+TREES[t.tree_type].days*86400000;\n  const ms=end-Date.now();\n  if(ms<=0)return \'Bitdi\';\n  const d=Math.floor(ms/86400000),h=Math.floor(ms%86400000/3600000),m=Math.floor(ms%3600000/60000);\n  return d+\'g \'+h+\'s \'+m+\'d\';\n}\nfunction wateredToday(t){return t.last_watered && new Date(t.last_watered).toDateString()===new Date().toDateString();}\nfunction harvestedToday(t){return t.last_harvest && (Date.now()-new Date(t.last_harvest).getTime())<86400000;}\n\nfunction renderPlots(trees){\n  const box=document.getElementById(\'myPlots\');\n  let html=\'\';\n  trees.forEach(t=>{\n    const info=TREES[t.tree_type];\n    html+=`<div class="plot">\n      <div class="emoji">${info.emoji}</div>\n      <div class="nm">${info.name}</div>\n      <div class="timer">⏳ ${daysLeft(t)}</div>\n      <div class="acts">\n        <button class="a-water" ${wateredToday(t)?\'disabled style=opacity:.5\':\'\'} onclick="water(${t.id})">💧 Su</button>\n        <button class="a-harvest" ${harvestedToday(t)?\'disabled style=opacity:.5\':\'\'} onclick="harvest(${t.id})">🪙 Yığ</button>\n      </div>\n    </div>`;\n  });\n  const empties=Math.max(0,9-trees.length);\n  for(let i=0;i<empties;i++)html+=`<div class="empty-plot" onclick="go(\'shop\')">＋ Ağac ək</div>`;\n  box.innerHTML=html;\n}\n\nasync function water(id){try{const d=await api(\'/api/trees/water/\'+id,\'POST\');toast(d.message);loadProfile();}catch(e){toast(e.message);}}\nasync function harvest(id){try{const d=await api(\'/api/trees/harvest/\'+id,\'POST\');toast(d.message);loadProfile();}catch(e){toast(e.message);}}\n\n/* SHOP */\nfunction renderShop(){\n  let html=\'\';\n  Object.entries(TREES).forEach(([id,t])=>{\n    html+=`<div class="card"><div class="shop-item">\n      <div class="emoji">${t.emoji}</div>\n      <div class="info">\n        <div class="t">${t.name}</div>\n        <div class="row">Qiymət: <b>${t.price} AZN</b></div>\n        <div class="row">Gündəlik gəlir: <b>${t.daily} AZN</b></div>\n        <div class="row">Müddət: <b>${t.days} gün</b></div>\n      </div>\n      <button class="buybtn" onclick="buy(${id})">al</button>\n    </div></div>`;\n  });\n  document.getElementById(\'shopList\').innerHTML=html;\n}\nasync function buy(id){\n  const t=TREES[id];\n  if(!confirm(t.name+\' (\'+t.price+\' AZN) almaq istəyirsiniz?\'))return;\n  try{const d=await api(\'/api/trees/buy\',\'POST\',{treeType:+id});toast(d.message);loadProfile();go(\'home\');}catch(e){toast(e.message);}\n}\n\n/* DEPOSIT */\nasync function submitDeposit(){\n  const amount=parseFloat(document.getElementById(\'depAmount\').value);\n  if(!amount||amount<10)return toast(\'Minimum depozit 10 AZN\');\n  try{const d=await api(\'/api/deposit\',\'POST\',{amount,method:\'Telegram @Delmontedepozit\'});\n    toast(d.message+\' → @Delmontedepozit\');document.getElementById(\'depAmount\').value=\'\';\n  }catch(e){toast(e.message);}\n}\n\n/* WITHDRAW */\nasync function submitWithdraw(){\n  const amount=parseFloat(document.getElementById(\'wAmount\').value);\n  const bankName=document.getElementById(\'wBank\').value.trim();\n  const cardHolder=document.getElementById(\'wHolder\').value.trim();\n  const cardNumber=document.getElementById(\'wCard\').value.trim();\n  if(!bankName||!cardHolder||!cardNumber)return toast(\'Bütün sahələri doldurun\');\n  if(!amount||amount<6)return toast(\'Minimum çıxarış 6 AZN\');\n  if(amount>2000)return toast(\'Maksimum çıxarış 2000 AZN\');\n  try{const d=await api(\'/api/withdraw\',\'POST\',{amount,bankName,cardHolder,cardNumber});\n    toast(\'Sorğu göndərildi! Net: \'+d.netAmount+\' AZN (Kom: \'+d.fee+\' AZN)\');\n    [\'wAmount\',\'wBank\',\'wHolder\',\'wCard\'].forEach(i=>document.getElementById(i).value=\'\');\n    loadProfile();\n  }catch(e){toast(e.message);}\n}\n\n/* REFERRAL */\nasync function loadReferral(){\n  try{const d=await api(\'/api/referral/stats\');\n    document.getElementById(\'refCount\').textContent=d.referralCount;\n    document.getElementById(\'refCash\').textContent=(+d.totalCashback).toFixed(2);\n    document.getElementById(\'myRefCode\').value=d.refCode;\n    document.getElementById(\'myRefLink\').value=location.origin+\'/?ref=\'+d.refCode;\n  }catch(e){toast(e.message);}\n}\nfunction copyVal(id){const el=document.getElementById(id);el.select();navigator.clipboard.writeText(el.value).then(()=>toast(\'Kopyalandı!\'));}\n\n/* TREASURE */\nasync function redeemCode(){\n  const code=document.getElementById(\'treCode\').value.trim();\n  if(!code)return toast(\'Kod daxil edin\');\n  try{const d=await api(\'/api/treasure/redeem\',\'POST\',{code});toast(d.message);document.getElementById(\'treCode\').value=\'\';loadProfile();}catch(e){toast(e.message);}\n}\n\n/* TX HISTORY */\nconst TXNAMES={deposit:\'Depozit\',withdraw:\'Çıxarış\',income:\'Gündəlik gəlir\',buy_tree:\'Ağac alışı\',referral_cashback:\'Referal cashback\',treasure:\'Xəzinə kodu\'};\nasync function loadTx(){\n  try{const d=await api(\'/api/transactions\');\n    if(!d.transactions.length){document.getElementById(\'txList\').innerHTML=\'<p style="color:#999;text-align:center">Əməliyyat yoxdur</p>\';return;}\n    const neg=[\'withdraw\',\'buy_tree\'];\n    document.getElementById(\'txList\').innerHTML=d.transactions.map(t=>{\n      const isNeg=neg.includes(t.type);\n      return `<div class="tx"><div><div>${TXNAMES[t.type]||t.type}</div><div class="d">${new Date(t.created_at).toLocaleString(\'az\')}</div></div>\n      <div style="text-align:right"><div class="amt ${isNeg?\'neg\':\'pos\'}">${isNeg?\'-\':\'+\'}${(+t.amount).toFixed(2)}</div>\n      <span class="badge b-${t.status}">${t.status===\'pending\'?\'gözləyir\':t.status===\'completed\'?\'tamam\':\'ləğv\'}</span></div></div>`;\n    }).join(\'\');\n  }catch(e){}\n}\n\n/* INIT */\nconst urlRef=new URLSearchParams(location.search).get(\'ref\');\nif(urlRef){showAuth(\'reg\');setTimeout(()=>{const el=document.getElementById(\'rgRef\');if(el)el.value=urlRef;},100);}\nif(token){enterApp();}\nsetInterval(()=>{if(profile)renderPlots(profile.trees);},60000);\n</script>\n</body>\n</html>\n'
LOGO_PNG = base64.b64decode('')
FARM_BG_JPG = base64.b64decode('')

