@app.post("/api/auth/register")
def register():
    data = request.get_json(silent=True) or {}
    phone = str(data.get("phone", "")).strip()
    password = str(data.get("password", ""))
    ref_code = str(data.get("refCode", "")).strip() or None

    if not phone or not password:
        return jsonify({"error": "Telefon və şifrə tələb olunur"}), 400
    if not re.fullmatch(r"994(50|51|55|70|77|99|10|12|40|44|60)\d{7}", phone):
        return jsonify({"error": "Nömrə yanlışdır. Nümunə: 994 55 5555555"}), 400
    if len(password) < 6 or len(password) > 20:
        return jsonify({"error": "Şifrə ən az 6, ən çox 20 simvol olmalıdır"}), 400

    hashed = bcrypt.hashpw(password.encode(), bcrypt.gensalt()).decode()
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT id FROM users WHERE phone = %s", (phone,))
            if cur.fetchone():
                return jsonify({"error": "Bu telefon nömrəsi artıq qeydiyyatdan keçib"}), 400
            referred_by = None
            if ref_code:
                cur.execute("SELECT id FROM users WHERE ref_code = %s", (ref_code,))
                ref = fetchone(cur)
                if ref:
                    referred_by = ref["id"]
            cur.execute(
                "INSERT INTO users (phone, password, balance, referred_by) VALUES (%s, %s, %s, %s) RETURNING *",
                (phone, hashed, Decimal("1.00"), referred_by),
            )
            user = fetchone(cur)
            if referred_by:
                cur.execute("INSERT INTO referrals (referrer_id, referred_id) VALUES (%s, %s)", (referred_by, user["id"]))
        return jsonify(json_safe({
            "success": True,
            "token": make_token(user["id"]),
            "user": {"id": user["id"], "phone": user["phone"], "balance": user["balance"], "refCode": user["ref_code"], "level": user["level"]},
            "message": "🎉 Qeydiyyat uğurlu! 1 AZN bonus əlavə edildi!",
        }))
    except Exception as exc:
        print("register error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/auth/login")
def login():
    data = request.get_json(silent=True) or {}
    phone = str(data.get("phone", "")).strip()
    password = str(data.get("password", ""))
    try:
        with db() as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT * FROM users WHERE phone = %s", (phone,))
            user = fetchone(cur)
        if not user or not bcrypt.checkpw(password.encode(), user["password"].encode()):
            return jsonify({"error": "Telefon və ya şifrə yanlışdır"}), 400
        return jsonify(json_safe({
            "success": True,
            "token": make_token(user["id"]),
            "user": {"id": user["id"], "phone": user["phone"], "balance": user["balance"], "refCode": user["ref_code"], "level": user["level"]},
        }))
    except Exception as exc:
        print("login error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.get("/api/user/profile")
def profile():
    user_id, err = require_user()
    if err:
        return err
    try:
        with db() as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT id, phone, balance, ref_code, level, total_deposit, total_withdraw, total_income FROM users WHERE id = %s", (user_id,))
            user = fetchone(cur)
            if not user:
                return jsonify({"error": "İstifadəçi tapılmadı"}), 404
            cur.execute("SELECT * FROM trees WHERE user_id = %s AND is_active = true", (user_id,))
            trees = fetchall(cur)
            cur.execute("SELECT COUNT(*) AS count FROM referrals WHERE referrer_id = %s", (user_id,))
            count = fetchone(cur)["count"]
        return jsonify(json_safe({"user": user, "trees": trees, "referralCount": int(count)}))
    except Exception as exc:
        print("profile error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/trees/buy")
def buy_tree():
    user_id, err = require_user()
    if err:
        return err
    data = request.get_json(silent=True) or {}
    try:
        tree_type = int(data.get("treeType"))
    except Exception:
        return jsonify({"error": "Yanlış ağac növü"}), 400
    tree = TREE_INFO.get(tree_type)
    if not tree:
        return jsonify({"error": "Yanlış ağac növü"}), 400
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT balance FROM users WHERE id = %s FOR UPDATE", (user_id,))
            user = fetchone(cur)
            if not user or Decimal(user["balance"]) < tree["price"]:
                return jsonify({"error": "Kifayət qədər balans yoxdur"}), 400
            cur.execute("UPDATE users SET balance = balance - %s WHERE id = %s", (tree["price"], user_id))
            cur.execute("INSERT INTO trees (user_id, tree_type, days_remaining, last_watered) VALUES (%s, %s, %s, NULL)", (user_id, tree_type, 30))
            cur.execute("INSERT INTO transactions (user_id, type, amount, description, status) VALUES (%s, %s, %s, %s, %s)", (user_id, "buy_tree", tree["price"], tree["name"] + " alındı", "completed"))
        return jsonify({"success": True, "message": tree["name"] + " əkildi!"})
    except Exception as exc:
        print("buy_tree error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/trees/water/<int:tree_id>")
def water_tree(tree_id):
    user_id, err = require_user()
    if err:
        return err
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT * FROM trees WHERE id = %s AND user_id = %s AND is_active = true", (tree_id, user_id))
            tree = fetchone(cur)
            if not tree:
                return jsonify({"error": "Ağac tapılmadı"}), 400
            last = tree.get("last_watered")
            if last and last.date() == datetime.now().date():
                return jsonify({"error": "Bu ağac bu gün artıq suvarılıb"}), 400
            cur.execute("UPDATE trees SET last_watered = NOW() WHERE id = %s AND user_id = %s", (tree_id, user_id))
        return jsonify({"success": True, "message": "Ağac suvarıldı! 💧"})
    except Exception as exc:
        print("water_tree error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/trees/harvest/<int:tree_id>")
def harvest_tree(tree_id):
    user_id, err = require_user()
    if err:
        return err
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT * FROM trees WHERE id = %s AND user_id = %s AND is_active = true", (tree_id, user_id))
            tree = fetchone(cur)
            if not tree:
                return jsonify({"error": "Ağac tapılmadı"}), 400
            info = TREE_INFO.get(int(tree["tree_type"]))
            if not info:
                return jsonify({"error": "Yanlış ağac növü"}), 400
            last = tree.get("last_harvest")
            if last and datetime.now() - last < timedelta(hours=24):
                return jsonify({"error": "Bu ağac artıq yığılıb, 24 saat gözləyin"}), 400
            daily = info["daily"]
            cur.execute("UPDATE users SET balance = balance + %s, total_income = total_income + %s WHERE id = %s", (daily, daily, user_id))
            cur.execute("UPDATE trees SET last_harvest = NOW() WHERE id = %s", (tree_id,))
            cur.execute("INSERT INTO transactions (user_id, type, amount, description, status) VALUES (%s, %s, %s, %s, %s)", (user_id, "income", daily, "Gündəlik gəlir", "completed"))
        return jsonify(json_safe({"success": True, "message": f"{daily} AZN gəlir toplandı!", "amount": daily}))
    except Exception as exc:
        print("harvest_tree error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/deposit")
def deposit():
    user_id, err = require_user()
    if err:
        return err
    data = request.get_json(silent=True) or {}
    try:
        amount = Decimal(str(data.get("amount", "0")))
    except Exception:
        amount = Decimal("0")
    if baku_hour() < 10 or baku_hour() >= 20:
        return jsonify({"error": "Depozit saatları 10:00 - 20:00 arasındadır"}), 400
    if amount < Decimal("10"):
        return jsonify({"error": "Minimum depozit 10 AZN-dir"}), 400
    try:
        with db(commit=True) as conn:
            cur = conn.cursor()
            cur.execute("INSERT INTO transactions (user_id, type, amount, description, status) VALUES (%s, %s, %s, %s, %s)", (user_id, "deposit", amount, data.get("method"), "pending"))
        return jsonify({"success": True, "message": "Depozit sorğusu göndərildi. Admin təsdiq edəcək.", "telegram": "@Delmontedepozit"})
    except Exception as exc:
        print("deposit error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/admin/approve-deposit/<int:tx_id>")
def approve_deposit(tx_id):
    data = request.get_json(silent=True) or {}
    admin_err = require_admin(data)
    if admin_err:
        return admin_err
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT * FROM transactions WHERE id = %s", (tx_id,))
            tx = fetchone(cur)
            if not tx:
                return jsonify({"error": "Əməliyyat tapılmadı"}), 404
            cur.execute("UPDATE users SET balance = balance + %s, total_deposit = total_deposit + %s WHERE id = %s", (tx["amount"], tx["amount"], tx["user_id"]))
            cur.execute("UPDATE transactions SET status = 'completed' WHERE id = %s", (tx_id,))
            cur.execute("SELECT referred_by FROM users WHERE id = %s", (tx["user_id"],))
            user = fetchone(cur)
            if user and user.get("referred_by"):
                cashback = Decimal(tx["amount"]) * Decimal("0.1")
                cur.execute("UPDATE users SET balance = balance + %s WHERE id = %s", (cashback, user["referred_by"]))
                cur.execute("INSERT INTO transactions (user_id, type, amount, description, status) VALUES (%s, %s, %s, %s, %s)", (user["referred_by"], "referral_cashback", cashback, "Referal cashback", "completed"))
                cur.execute("UPDATE referrals SET deposit_amount = deposit_amount + %s, cashback_earned = cashback_earned + %s WHERE referred_id = %s", (tx["amount"], cashback, tx["user_id"]))
        return jsonify({"success": True, "message": "Depozit təsdiq edildi"})
    except Exception as exc:
        print("approve_deposit error:", exc)
        return jsonify({"error": "Server xətası"}), 500


@app.post("/api/withdraw")
def withdraw():
    user_id, err = require_user()
    if err:
        return err
    data = request.get_json(silent=True) or {}
    try:
        amount = Decimal(str(data.get("amount", "0")))
    except Exception:
        amount = Decimal("0")
    if baku_hour() < 10 or baku_hour() >= 20:
        return jsonify({"error": "Çıxarış saatları 10:00 - 20:00 arasındadır"}), 400
    if amount < Decimal("6"):
        return jsonify({"error": "Minimum çıxarış 6 AZN-dir"}), 400
    if amount > Decimal("2000"):
        return jsonify({"error": "Maksimum çıxarış 2000 AZN-dir"}), 400
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT balance FROM users WHERE id = %s FOR UPDATE", (user_id,))
            user = fetchone(cur)
            if not user or amount > Decimal(user["balance"]):
                return jsonify({"error": "Kifayət qədər balans yoxdur"}), 400
            fee = amount * Decimal("0.1")
            net = amount - fee
            cur.execute("UPDATE users SET balance = balance - %s, total_withdraw = total_withdraw + %s WHERE id = %s", (amount, amount, user_id))
            cur.execute("INSERT INTO transactions (user_id, type, amount, bank_name, card_holder, card_number, description, status) VALUES (%s, %s, %s, %s, %s, %s, %s, %s)", (user_id, "withdraw", amount, data.get("bankName"), data.get("cardHolder"), data.get("cardNumber"), f"Net: {net} AZN (Kom: {fee} AZN)", "pending"))
        return jsonify(json_safe({"success": True, "message": "Çıxarış sorğusu göndərildi!", "netAmount": net, "fee": fee}))
    except Exception as exc:
        print("withdraw error:", exc)
        return jsonify({"error": "Server xətası"}), 500


