@app.post("/api/treasure/redeem")
def redeem_code():
    user_id, err = require_user()
    if err:
        return err
    data = request.get_json(silent=True) or {}
    code = str(data.get("code", "")).strip()
    if not code:
        return jsonify({"error": "Kod daxil edin"}), 400
    try:
        with db(commit=True) as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT * FROM treasure_codes WHERE code = %s AND is_active = true FOR UPDATE", (code,))
            tc = fetchone(cur)
            if not tc:
                return jsonify({"error": "Kod tapılmadı və ya aktiv deyil"}), 400
            if tc["used_count"] >= tc["max_uses"]:
                return jsonify({"error": "Bu kodun istifadə limiti bitib"}), 400
            cur.execute("SELECT 1 FROM code_redemptions WHERE code_id = %s AND user_id = %s", (tc["id"], user_id))
            if cur.fetchone():
                return jsonify({"error": "Bu kodu artıq istifadə etmisiniz"}), 400
            cur.execute("INSERT INTO code_redemptions (code_id, user_id) VALUES (%s, %s)", (tc["id"], user_id))
            cur.execute("UPDATE treasure_codes SET used_count = used_count + 1 WHERE id = %s", (tc["id"],))
            cur.execute("UPDATE users SET balance = balance + %s WHERE id = %s", (tc["amount"], user_id))
            cur.execute("INSERT INTO transactions (user_id, type, amount, description, status) VALUES (%s, %s, %s, %s, %s)", (user_id, "treasure", tc["amount"], "Xəzinə kodu: " + tc["code"], "completed"))
        return jsonify(json_safe({"success": True, "message": f"{tc['amount']} AZN hesabınıza əlavə edildi!", "amount": tc["amount"]}))
    except Exception as exc:
        print("redeem_code error:", exc)
        return jsonify({"error": "Server xətası"}), 500


