@app.get("/api/admin/pending")
def admin_pending():
    admin_err = require_admin()
    if admin_err:
        return admin_err
    try:
        with db() as conn:
            cur = conn.cursor(row_factory=dict_row)
            cur.execute("SELECT t.*, u.phone FROM transactions t JOIN users u ON t.user_id = u.id WHERE t.type = 'deposit' AND t.status = 'pending' ORDER BY t.created_at DESC")
            deposits = fetchall(cur)
            cur.execute("SELECT t.*, u.phone FROM transactions t JOIN users u ON t.user_id = u.id WHERE t.type = 'withdraw' AND t.status = 'pending' ORDER BY t.created_at DESC")
            withdraws = fetchall(cur)
        return jsonify(json_safe({"deposits": deposits, "withdraws": withdraws}))
    except Exception as exc:
        print("admin_pending error:", exc)
        return jsonify({"error": "Server xətası"}), 500


